"""Tests for modelzoo_ranker.data.split — model-level train/val/test assignment."""
from modelzoo_ranker.data.split import (
    assign_splits, DEFAULT_VAL_MODELS, DEFAULT_TEST_MODELS,
)


class TestAssignSplits:
    def test_assign_splits_default(self, dataset_dir):
        """Default split assigns groups by model name."""
        from modelzoo_ranker.data.loader import load_all_models
        groups = load_all_models(dataset_dir)
        split_groups = assign_splits(groups)

        # All fixture models (A, B, C, D) are not in default val/test lists,
        # so all should be in train
        for g in split_groups:
            assert g['split'] == 'train'

    def test_assign_splits_custom(self, dataset_dir):
        """Custom val/test model lists assign correctly."""
        from modelzoo_ranker.data.loader import load_all_models
        groups = load_all_models(dataset_dir)
        split_groups = assign_splits(
            groups,
            val_models=['ModelA'],
            test_models=['ModelB'],
        )

        for g in split_groups:
            if g['model'] == 'ModelA':
                assert g['split'] == 'val'
            elif g['model'] == 'ModelB':
                assert g['split'] == 'test'
            else:
                assert g['split'] == 'train'

    def test_default_model_lists(self):
        """Default val/test model lists are defined."""
        assert 'YOLOv8n' in DEFAULT_VAL_MODELS
        assert 'MobileNet_v3_int8' in DEFAULT_VAL_MODELS
        assert 'ResNet-50' in DEFAULT_TEST_MODELS
        assert 'DenseNet' in DEFAULT_TEST_MODELS

